1	import AVFoundation
2	import Accelerate
3	import Foundation
4	
5	/// Sendable chunk extracted on the audio tap thread before being handed to the actor.
6	private struct ConvertedChunk: Sendable {
7	    let samples: [Float]
8	    let rms: Float
9	    let peak: Float
10	}
11	
12	actor AudioRecorder {
13	    enum RecorderError: Error, LocalizedError {
14	        case engineStartFailed(String)
15	        case converterCreationFailed
16	        case formatUnsupported
17	        case writerFailed(String)
18	        case notRecording
19	
20	        var errorDescription: String? {
21	            switch self {
22	            case .engineStartFailed(let msg): return "Audio engine failed to start: \(msg)"
23	            case .converterCreationFailed: return "Failed to create audio converter."
24	            case .formatUnsupported: return "Microphone audio format is unsupported."
25	            case .writerFailed(let msg): return "Failed to write WAV file: \(msg)"
26	            case .notRecording: return "No active recording."
27	            }
28	        }
29	    }
30	
31	    struct LevelSample: Sendable {
32	        var rms: Float
33	        var peak: Float
34	        var timestamp: TimeInterval
35	    }
36	
37	    private let targetSampleRate: Double = 16000
38	    private let engine = AVAudioEngine()
39	    private var outputBuffers: [Float] = []
40	    private var levelCallback: (@Sendable (LevelSample) -> Void)?
41	    private var startedAt: Date?
42	    private var isRecording: Bool = false
43	
44	    func start(levelCallback: (@Sendable (LevelSample) -> Void)? = nil) async throws {
45	        if isRecording { return }
46	        outputBuffers.removeAll(keepingCapacity: true)
47	        self.levelCallback = levelCallback
48	
49	        let input = engine.inputNode
50	        let inputFormat = input.outputFormat(forBus: 0)
51	        guard inputFormat.sampleRate > 0 else {
52	            throw RecorderError.formatUnsupported
53	        }
54	
55	        guard let targetFormat = AVAudioFormat(
56	            commonFormat: .pcmFormatFloat32,
57	            sampleRate: targetSampleRate,
58	            channels: 1,
59	            interleaved: false
60	        ) else {
61	            throw RecorderError.converterCreationFailed
62	        }
63	
64	        guard let converter = AVAudioConverter(from: inputFormat, to: targetFormat) else {
65	            throw RecorderError.converterCreationFailed
66	        }
67	
68	        // Capture sendable copies for use inside the audio tap.
69	        let capturedTargetFormat = targetFormat
70	        let capturedConverter = UncheckedSendableBox(value: converter)
71	        let recorderRef = self
72	
73	        input.removeTap(onBus: 0)
74	        input.installTap(onBus: 0, bufferSize: 1024, format: inputFormat) { buffer, _ in
75	            guard let chunk = AudioRecorder.convert(buffer: buffer, converter: capturedConverter.value, targetFormat: capturedTargetFormat) else { return }
76	            Task { await recorderRef.ingest(chunk: chunk) }
77	        }
78	
79	        do {
80	            engine.prepare()
81	            try engine.start()
82	        } catch {
83	            input.removeTap(onBus: 0)
84	            throw RecorderError.engineStartFailed(error.localizedDescription)
85	        }
86	        startedAt = Date()
87	        isRecording = true
88	    }
89	
90	    func stop() async throws -> RecordingResult {
91	        guard isRecording else { throw RecorderError.notRecording }
92	        engine.inputNode.removeTap(onBus: 0)
93	        engine.stop()
94	        isRecording = false
95	        let started = startedAt ?? Date()
96	        // Drain a brief grace period so in-flight tap Tasks land in outputBuffers before we copy.
97	        try? await Task.sleep(nanoseconds: 60_000_000)
98	        let samples = outputBuffers
99	        outputBuffers.removeAll(keepingCapacity: false)
100	        let peak = samples.max(by: { abs($0) < abs($1) }).map(abs) ?? 0
101	        let duration = Double(samples.count) / targetSampleRate
102	        NSLog("ThinkAloud: AudioRecorder.stop samples=\(samples.count) peak=\(peak) duration=\(duration)s")
103	        return RecordingResult(
104	            samples: samples,
105	            sampleRate: Int(targetSampleRate),
106	            channels: 1,
107	            durationSeconds: duration,
108	            startedAt: started
109	        )
110	    }
111	
112	    func cancel() async {
113	        if isRecording {
114	            engine.inputNode.removeTap(onBus: 0)
115	            engine.stop()
116	            isRecording = false
117	        }
118	        outputBuffers.removeAll(keepingCapacity: false)
119	        startedAt = nil
120	        levelCallback = nil
121	    }
122	
123	    var elapsedSeconds: TimeInterval {
124	        guard let startedAt else { return 0 }
125	        return -startedAt.timeIntervalSinceNow
126	    }
127	
128	    fileprivate func ingest(chunk: ConvertedChunk) {
129	        outputBuffers.append(contentsOf: chunk.samples)
130	        if let levelCallback {
131	            let ts = startedAt.map { -$0.timeIntervalSinceNow } ?? 0
132	            levelCallback(LevelSample(rms: chunk.rms, peak: chunk.peak, timestamp: ts))
133	        }
134	    }
135	
136	    fileprivate nonisolated static func convert(buffer: AVAudioPCMBuffer, converter: AVAudioConverter, targetFormat: AVAudioFormat) -> ConvertedChunk? {
137	        let ratio = targetFormat.sampleRate / buffer.format.sampleRate
138	        let capacity = AVAudioFrameCount(Double(buffer.frameLength) * ratio + 1024)
