1	import Foundation
2	import Observation
3	
4	/// Drives the dataset browser window: paged list, multi-selection, edit, delete.
5	@MainActor
6	@Observable
7	final class DatasetBrowserController {
8	    private let datasetStore: DatasetStore
9	    private let audioFileStore: AudioFileStore
10	
11	    private(set) var records: [DatasetRecord] = []
12	    private(set) var hasMore: Bool = true
13	    private(set) var isLoading: Bool = false
14	    private(set) var errorMessage: String?
15	    /// One-shot indicator pulses for ~1.5s after a successful edit save. Lets the detail view
16	    /// show "已儲存 ✓" briefly without us threading a separate callback.
17	    private(set) var lastSaveTick: Date?
18	
19	    /// Multi-selection set bound to the SwiftUI List. Detail panel renders only when exactly
20	    /// one row is selected; bulk delete uses the full set.
21	    var selectedIDs: Set<String> = []
22	
23	    /// Plain Bool — the layout is a HStack, not NavigationSplitView, so we don't need the
24	    /// three-state NavigationSplitViewVisibility. Toggled by the toolbar sidebar button.
25	    var sidebarHidden: Bool = false
26	    /// Toolbar push button sets true → SwiftUI .sheet displays HFPushView and resets to false.
27	    var requestPushSheet: Bool = false
28	    /// Toolbar delete button populates this → SwiftUI .confirmationDialog handles it.
29	    var pendingDeleteRequestIDs: Set<String> = []
30	
31	    private let pageSize: Int = 50
32	
33	    init(datasetStore: DatasetStore, audioFileStore: AudioFileStore) {
34	        self.datasetStore = datasetStore
35	        self.audioFileStore = audioFileStore
36	    }
37	
38	    /// Returns the unique selected record, or nil when 0 or >1 are selected.
39	    var selectedRecord: DatasetRecord? {
40	        guard selectedIDs.count == 1, let id = selectedIDs.first else { return nil }
41	        return records.first(where: { $0.id == id })
42	    }
43	
44	    /// Aggregate stats for the footer/status bar — total record count and combined audio size.
45	    var totalDurationMs: Int {
46	        records.reduce(0) { $0 + ($1.durationMs ?? 0) }
47	    }
48	
49	    /// Resets to first page. Call when window opens or after a destructive change.
50	    func reload() async {
51	        records = []
52	        hasMore = true
53	        selectedIDs = []
54	        errorMessage = nil
55	        await loadMore()
56	    }
57	
58	    /// Loads the next page. Idempotent if already loading or no more data.
59	    func loadMore() async {
60	        if isLoading || !hasMore { return }
61	        isLoading = true
62	        defer { isLoading = false }
63	        do {
64	            let page = try await datasetStore.page(offset: records.count, limit: pageSize)
65	            records.append(contentsOf: page)
66	            if page.count < pageSize {
67	                hasMore = false
68	            }
69	        } catch {
70	            errorMessage = String(localized: "Failed to load records: \(error.localizedDescription)")
71	        }
72	    }
73	
74	    /// Deletes one record and its audio file.
75	    func delete(id: String) async {
76	        await deleteAll(ids: [id])
77	    }
78	
79	    /// Bulk delete: removes each record's row from the DB, its audio file, and drops the id
80	    /// from the selection set.
81	    func deleteAll(ids: Set<String>) async {
82	        errorMessage = nil
83	        for id in ids {
84	            do {
85	                let record = try await datasetStore.fetch(id: id)
86	                try await datasetStore.delete(id: id)
87	                if let record {
88	                    try? await audioFileStore.delete(relativePath: record.audioPath)
89	                }
90	                records.removeAll { $0.id == id }
91	                selectedIDs.remove(id)
92	            } catch {
93	                errorMessage = String(localized: "Delete failed: \(error.localizedDescription)")
94	                return
95	            }
96	        }
97	    }
98	
99	    /// Overwrites just the edited transcript. raw is preserved.
100	    func updateEdited(id: String, text: String) async {
101	        errorMessage = nil
102	        do {
103	            try await datasetStore.update(id: id, editedTranscript: text)
104	            if let i = records.firstIndex(where: { $0.id == id }) {
105	                let r = records[i]
106	                records[i] = DatasetRecord(
107	                    id: r.id,
108	                    createdAt: r.createdAt,
109	                    audioPath: r.audioPath,
110	                    durationMs: r.durationMs,
111	                    sampleRate: r.sampleRate,
112	                    channels: r.channels,
113	                    sourceAppBundleID: r.sourceAppBundleID,
114	                    sourceAppName: r.sourceAppName,
115	                    asrProvider: r.asrProvider,
116	                    asrModel: r.asrModel,
117	                    asrRuntime: r.asrRuntime,
118	                    asrConfigJSON: r.asrConfigJSON,
119	                    rawTranscript: r.rawTranscript,
120	                    editedTranscript: text,
121	                    inserted: r.inserted,
122	                    savedToDataset: r.savedToDataset,
123	                    language: r.language,
124	                    metadataJSON: r.metadataJSON
125	                )
126	            }
127	            lastSaveTick = Date()
128	        } catch {
129	            errorMessage = String(localized: "Save failed: \(error.localizedDescription)")
130	        }
131	    }
132	
133	    /// Resolves the absolute on-disk URL for a record's audio file.
134	    func audioURL(for record: DatasetRecord) async -> URL {
135	        await audioFileStore.absoluteURL(for: record.audioPath)
136	    }
137	
138	    // MARK: - Toolbar-driven actions
139	
140	    func toggleSidebar() {
141	        sidebarHidden.toggle()
142	    }
143	
144	    func requestPush() {
145	        requestPushSheet = true
146	    }
147	
148	    func requestDeleteSelected() {
149	        guard !selectedIDs.isEmpty else { return }
