struct LevelMeterView: View {
    let rms: Float
    let peak: Float

    var body: some View {
        GeometryReader { geo in
            let rmsWidth = CGFloat(min(max(rms * 3, 0), 1)) * geo.size.width
            let peakWidth = CGFloat(min(max(peak * 2, 0), 1)) * geo.size.width
            ZStack(alignment: .leading) {
