4	import MLXAudioCore
5	import MLXAudioSTT
6	
7	/// Wraps a non-Sendable reference so it can cross the actor isolation boundary on load.
8	/// We only touch the wrapped model inside MLXAudioQwenRuntime, so confining it to a single actor is safe.
9	private struct UncheckedBox<T>: @unchecked Sendable {
10	    let value: T
11	}
12	
13	/// Free function so the actor can `await` a Sendable wrapper instead of the raw non-Sendable model.
14	private func loadQwenModel(modelID: String, cache: HubCache) async throws -> UncheckedBox<Qwen3ASRModel> {
15	    let model = try await Qwen3ASRModel.fromPretrained(modelID, cache: cache)
16	    return UncheckedBox(value: model)
17	}
18	
19	actor MLXAudioQwenRuntime: ASRRuntime {
20	    let id: String = "mlx-audio-swift-qwen3-asr"
21	    let modelID: String
22	    private let cache: HubCache
23	    private let cacheDirectory: URL?
24	
25	    private var model: UncheckedBox<Qwen3ASRModel>?
26	    private var currentStatus: ASRRuntimeStatus = .unloaded
27	    private var expectedTotalBytes: Int64?
28	
29	    init(modelID: String, cacheDirectory: URL? = nil) {
